import React, { Component } from "react";
import "./nav.css";

function Nav() {
  function Modal() {}
  const [open, setOpen] = React.useState(false);
  return (
    <div onClick={() => setOpen(!open)} className="gg-menu-grid-o">
      {open && <Modal in={open}>Click anywhere to close</Modal>}
    </div>
  );
}

export default Nav;

